import React from 'react'
import { useState } from 'react';
import './FoodLog.css';
import { createRoot } from 'react-dom/client';
var numberofMeals = 0;
const socket = new WebSocket('ws://localhost:8080');
socket.binaryType = "arraybuffer";

socket.addEventListener('open', event =>{
    console.log("Socket connection open.")
});

socket.addEventListener('message', event => {
  var searchResults
  console.log('Message from server: ', event.data);
  if(event.data.slice(0,"SEARCH_RESULTS:".length)=="SEARCH_RESULTS:"){
    searchResults = JSON.parse(event.data.slice("SEARCH_RESULTS:".length,event.data.length));
    console.log(searchResults);
  };
  
});



const FoodLog = () => {
  const [meals, addMeal] = useState();

  function handleClick() {
    var mealName = document.getElementById("mealInput").value;
    addMeal(meals.push());
  }

  return (
    <div>
      <input name="mealInput" id="mealInput"></input>
      <button onClick={handleClick}></button>
    </div>
  )
}

export default FoodLog
